import pandas as pd
import numpy as np


def compute(rows, specs):
    """Annualized realized volatility: rolling stddev of daily returns.

    Causal by construction: the value at date t uses only returns from the
    trailing `period` window ending at t (sqrt(252)-annualized, sample stddev).

    Args:
        rows: Price data with 'date' and 'close' or 'adjusted_close'
        specs: List of specs with 'period' (default 20) and 'column'

    Returns:
        List of {date, <column>: value} dicts; warm-up rows omitted.
    """
    if not rows:
        return []

    df = pd.DataFrame(rows)
    if df.empty:
        return []
    df = df.sort_values("date").reset_index(drop=True)

    close_col = (
        "adjusted_close"
        if "adjusted_close" in df.columns and df["adjusted_close"].notna().any()
        else "close"
    )
    close = pd.to_numeric(df[close_col], errors="coerce")
    returns = close.pct_change()

    results = []
    cols = {}
    for spec in specs:
        period = int(spec.get("period", 20))
        col_name = spec.get("column", f"realized_vol_{period}")
        # rolling sample stddev of returns, annualized
        cols[col_name] = returns.rolling(window=period, min_periods=period).std(
            ddof=1
        ) * np.sqrt(252.0)

    for i in range(len(df)):
        result = {"date": df.at[i, "date"]}
        for col_name, series in cols.items():
            val = series.iloc[i]
            if pd.notna(val):
                result[col_name] = float(val)
        if len(result) > 1:
            results.append(result)

    return results
